// Strip markdown code blocks if present
const cleaned = raw
  .replace(/```json\n?/g, '')
  .replace(/```\n?/g, '')
  .trim();

// Find the JSON object
const start = cleaned.indexOf('{');
const end = cleaned.lastIndexOf('}');
const jsonStr = cleaned.slice(start, end + 1);

return [{ json: JSON.parse(jsonStr) }];

